const input =
  $json.chatInput ??
  $json.body?.chatInput ??
  $json.text ??
  '';

const text = String(input).trim();

// Find a domain anywhere in the message (e.g., "acme.com")
const domainMatch = text.match(/([a-z0-9-]+\.)+[a-z]{2,}/i);
const domain = domainMatch ? domainMatch[0].toLowerCase() : null;

// If user included a domain, remove it from the remaining text; the rest is the query/name
const companyQuery = domain ? text.replace(domainMatch[0], '').trim() : text;

return [{
  json: {
    input: text,
    domain,
    companyQuery: companyQuery || text
  }
}];

const items = $input.all();
if (!items.length) return [{ json: { error: "No items received" } }];

// Parse fields should be present either in each merged item, or only on the first.
const first = items[0].json;

const input = String(first.input || '').trim();
const queryRaw = String(first.companyQuery || '').trim();
const query = queryRaw.toLowerCase();
const userDomain = first.domain ? String(first.domain).trim().toLowerCase() : null;

const norm = (s) => String(s || '').trim().toLowerCase();
const toDomain = (value) =>
  String(value || '')
    .trim()
    .toLowerCase()
    .replace(/^https?:\/\//, '')
    .replace(/^www\./, '')
    .split('/')[0] || null;

const scoreCompany = (name, domain, website) => {
  const n = norm(name);
  const d = norm(domain);
  const w = norm(website);

  if (!query) return 0;
  if (n === query) return 100;
  if (n.includes(query)) return 70;
  if (query.includes(n) && n.length >= 3) return 50;
  if (d.includes(query) || w.includes(query)) return 40;
  return 0;
};

let best = null;
let bestScore = 0;

for (const it of items) {
  const c = it.json;

  // Company data might be in properties, or might have been merged differently
  const props = c.properties ?? c;

  // If this item doesn't look like a company, skip it
  const hasCompanySignal = props.name || props.domain || props.website || c.id || props.hs_object_id;
  if (!hasCompanySignal) continue;

  const s = scoreCompany(props.name, props.domain, props.website);
  if (s > bestScore) {
    bestScore = s;
    best = c;
  }
}

const bestProps = best?.properties ?? {};
const pickedDomain = toDomain(bestProps.domain) || toDomain(bestProps.website);

return [{
  json: {
    input,
    companyQuery: queryRaw,
    domain: userDomain || pickedDomain,
    companyName: bestProps.name || null,
    companyId: best?.id || bestProps.hs_object_id || null,
    matchScore: best ? bestScore : 0,
    matchSource: userDomain ? "user_domain" : (best ? "hubspot_batch_match" : "none")
  }
}];

const hs = $input.first().json;

// Flatten HubSpot properties
const propsRaw = hs.properties || {};
const flatProps = {};
for (const [k, v] of Object.entries(propsRaw)) {
  flatProps[k] = (v && typeof v === 'object' && 'value' in v) ? v.value : v;
}

return [{
  json: {
    // what the agent should use directly
    domain: flatProps.domain || flatProps.website || "",
    companyId: hs.companyId || null,
    account_name: flatProps.name || "Unknown",
    lifecyclestage: flatProps.lifecyclestage || "Unknown",

    // keep the full payload for reference (optional)
    hubspot: {
      companyId: hs.companyId || null,
      portalId: hs.portalId || null,
      properties: flatProps
    }
  }
}];

