(() => {
  const a = $json.output ? JSON.parse($json.output) : null;
  const taskId = $json.engagement?.id ?? null;

  if (!a) return "Account 360 ran, but AI output was missing from this Slack step.";

  return (
    "*Account 360 created in HubSpot*\n" +
    "*Account:* " + (a.account_name || "Unknown") + "\n" +
    "*Domain:* " + (a.domain || "Unknown") + "\n" +
    "*Stage:* " + (a.stage || "Unknown") + "\n" +
    "*Health:* " + (a.health_score || "Unknown") + "\n" +
    (taskId ? ("*Task ID:* " + taskId + "\n") : "") +
    "\n*Summary:*\n" + (a.summary || "") + "\n\n" +
    "*Top next actions:*\n- " +
    (a.next_actions || [])
      .slice(0,2)
      .map(x => `${x.channel}: ${x.reason}`)
      .join("\n- ")
  );
})()
}}
